import java.sql.*;

public class SQLInjectionSecure {

    public static void main(String[] args) {
        try {
            String userInput = args[0]; // Simulating user input here

            // Establishing a connection to the database
            Connection conn = DriverManager.getConnection("jdbc:mysql://localhost:3306/mydatabase", "username", "password");

            // Using a prepared statement with parameterized query
            String query = "SELECT * FROM users WHERE username = ?";
            PreparedStatement pstmt = conn.prepareStatement(query);
            pstmt.setString(1, userInput); // Set the parameter value safely

            // Executing the query and processing the results
            ResultSet rs = pstmt.executeQuery();
            while (rs.next()) {
                System.out.println("User found: " + rs.getString("username"));
            }

            conn.close();
        } catch (SQLException e) {
            e.printStackTrace();
        }
    }
}

